export class ConsoleMetricExporter {
  export(_metrics, callback) {
    callback?.({ code: 0 });
  }
  async shutdown() {}
}

export class PeriodicExportingMetricReader {
  constructor(options = {}) {
    this.options = options;
  }
  async shutdown() {}
}

export class MeterProvider {
  constructor(options = {}) {
    this.options = options;
  }
  getMeter() {
    return {
      createCounter() { return { add() {} }; },
      createHistogram() { return { record() {} }; },
      createUpDownCounter() { return { add() {} }; },
    };
  }
  async shutdown() {}
}
